# ── 命令注册表 ─────────────────────────────────
"""集中定义所有斜杠命令的元数据，供智能补全与帮助系统使用。

每条命令包含：
  desc:   简短描述（补全列表显示）
  usage:  用法示例
  detail: 详细说明（预选中时显示）
  modes:  适用模式（None 表示所有模式）
"""

from __future__ import annotations

from typing import Any


def _cmd(
    desc: str,
    usage: str,
    detail: str,
    modes: list[str] | None = None,
) -> dict[str, Any]:
    return {"desc": desc, "usage": usage, "detail": detail, "modes": modes}


# 所有命令按字母序排列
COMMAND_REGISTRY: dict[str, dict[str, Any]] = {
    "/chapter": _cmd(
        "跳转章节", "/chapter <n>", "跳转查看小说第 n 章内容", ["novel"]
    ),
    "/clear": _cmd(
        "清空历史", "/clear", "清空当前会话的对话历史（不删除会话本身）"
    ),
    "/delete": _cmd(
        "删除会话", "/delete <id>", "删除指定 ID 的会话（不能删除当前会话）"
    ),
    "/effort": _cmd(
        "思考强度", "/effort high|max", "设置思考强度：high 或 max"
    ),
    "/follow": _cmd(
        "预览跟随", "/follow on|off", "开关小说文件预览的自动跟随功能", ["novel"]
    ),
    "/help": _cmd(
        "查看帮助", "/help", "显示当前模式的命令帮助"
    ),
    "/info": _cmd(
        "会话信息", "/info", "显示当前会话、模型、上下文占用等信息"
    ),
    "/load": _cmd(
        "载入会话/文件", "/load <id|file>", "载入历史会话（传 ID）或加载文件到上下文（传路径）"
    ),
    "/ls": _cmd(
        "历史会话", "/ls", "弹出模态屏选择/载入历史会话（同 /sessions）"
    ),
    "/model": _cmd(
        "切换模型", "/model <name>", "切换 DeepSeek 模型"
    ),
    "/mode": _cmd(
        "切换模式", "/mode chat|novel", "切换到聊天或小说创作模式"
    ),
    "/new": _cmd(
        "新建会话", "/new [名称]", "创建新的对话会话，可选指定名称"
    ),
    "/novel": _cmd(
        "小说项目", "/novel new|file|open <...>", "新建/打开小说项目", ["novel"]
    ),
    "/panel": _cmd(
        "面板控制", "/panel ratio <n>", "调整左右分栏比例", ["novel"]
    ),
    "/plan": _cmd(
        "计划模式", "/plan <请求>", "模型先制定计划到 .Project/，确认后执行", ["novel"]
    ),
    "/preset": _cmd(
        "预设管理", "/preset list|use|add|del|show", "管理角色预设"
    ),
    "/quit": _cmd(
        "退出", "/quit", "退出 K.A-purn-tui"
    ),
    "/rename": _cmd(
        "重命名会话", "/rename <名称>", "重命名当前会话"
    ),
    "/sessions": _cmd(
        "历史会话", "/sessions", "弹出模态屏选择/载入历史会话"
    ),
    "/system": _cmd(
        "系统提示词", "/system <prompt>", "设置当前模式的系统提示词"
    ),
    "/think": _cmd(
        "思考开关", "/think on|off", "开关 DeepSeek 思考模式"
    ),
}


def match_commands(prefix: str, mode: str | None = None) -> list[tuple[str, dict[str, Any]]]:
    """返回与 prefix 匹配的命令列表（前缀匹配）。

    Args:
        prefix: 用户输入的命令前缀（如 "/n"）
        mode: 当前模式名，用于过滤模式专属命令；None 不过滤

    Returns:
        [(command, meta), ...] 按字母序排列
    """
    if not prefix.startswith("/"):
        return []
    results = []
    for cmd, meta in COMMAND_REGISTRY.items():
        if not cmd.startswith(prefix) and not prefix.startswith(cmd):
            # 前缀匹配：命令以 prefix 开头
            if not cmd.startswith(prefix):
                continue
        if cmd.startswith(prefix):
            # 模式过滤
            cmd_modes = meta.get("modes")
            if mode and cmd_modes and mode not in cmd_modes:
                continue
            results.append((cmd, meta))
    return sorted(results, key=lambda x: x[0])

# ── 模式系统基类 ─────────────────────────────────
"""Mode 抽象基类：定义该模式下的 system prompt、可用工具、右侧面板、命令。"""

from __future__ import annotations

from abc import ABC, abstractmethod
from typing import TYPE_CHECKING

if TYPE_CHECKING:
    from textual.widget import Widget


class Mode(ABC):
    """模式基类。App 持有 current_mode，切换时 recompose 右侧容器并重建工具集。"""

    name: str = ""
    display_name: str = ""

    @abstractmethod
    def get_system_prompt(self) -> str:
        """返回该模式的 system prompt。"""
        ...

    @abstractmethod
    def get_tools(self) -> list[dict]:
        """返回 OpenAI tools schema 列表（可为空）。"""
        ...

    @abstractmethod
    def get_right_panels(self) -> list[type[Widget]]:
        """返回该模式右侧要显示的面板 widget 类列表（可为空）。"""
        ...

    def get_help(self) -> str:
        """该模式下的帮助文本。"""
        return ""

# ── 右侧面板基类 ─────────────────────────────────
"""BaseRightPanel：右侧面板基类。可滚动，App 在工具执行后调用 refresh_state 刷新内容。"""

from __future__ import annotations

from textual.app import ComposeResult
from textual.containers import ScrollableContainer
from textual.widgets import Static

from ..state.novel_state import NovelState


class BaseRightPanel(ScrollableContainer):
    """右侧面板基类：可滚动容器，内部 Static 显示内容。子类实现 render_content。"""

    DEFAULT_CSS = """
    BaseRightPanel {
        border: round $primary;
        padding: 0 1;
        height: 2fr;
        scrollbar-size: 1 1;
    }
    BaseRightPanel > #panel-content {
        height: auto;
        padding: 0;
        border: none;
    }
    """

    title: str = "面板"

    def __init__(self) -> None:
        super().__init__()
        self._state: NovelState | None = None

    def compose(self) -> ComposeResult:
        yield Static("", id="panel-content", markup=True)

    @property
    def content(self) -> Static:
        return self.query_one("#panel-content", Static)

    def refresh_state(self, state: NovelState) -> None:
        """App 调用：用最新状态刷新本面板。"""
        self._state = state
        try:
            self.content.update(self.render_content())
        except Exception:
            # compose 尚未完成，延迟刷新
            self.call_after_refresh(self._do_refresh)

    def _do_refresh(self) -> None:
        if self._state is not None:
            try:
                self.content.update(self.render_content())
            except Exception:
                pass

    def render_content(self) -> str:
        """子类实现：返回面板内容（支持 markup）。"""
        return ""

# ── 章节进度面板 ─────────────────────────────────
"""ChapterPanel：显示总章数、当前章节高亮、完成进度条。"""

from __future__ import annotations

from .base import BaseRightPanel


class ChapterPanel(BaseRightPanel):
    """章节进度面板（fraction 1，紧凑）。"""

    DEFAULT_CSS = """
    ChapterPanel {
        border: round $accent;
        height: 1fr;
        min-height: 3;
    }
    """

    title = "章节进度"

    def render_content(self) -> str:
        if self._state is None or self._state.chapter_count == 0:
            return "[dim]尚未设定章节数[/dim]"
        s = self._state
        # 优先使用模型报告的自定义进度，否则回退到 done_chapter_count
        pg_current = s.progress_current if s.progress_total > 0 else s.done_chapter_count
        pg_total = s.progress_total if s.progress_total > 0 else s.chapter_count
        pct = (pg_current / pg_total * 100) if pg_total > 0 else 0
        # 进度条（20 格）
        bar_len = 20
        filled = int(bar_len * pct / 100)
        bar = "▓" * filled + "░" * (bar_len - filled)
        cur = s.current_chapter
        label = s.progress_label if s.progress_label else (f"第 {cur} 章填充中" if cur else "空闲")
        lines = [f"[bold]{label}[/bold]  [cyan]{pg_current}/{pg_total}[/cyan]  {pct:.0f}%", f"[{bar}]"]
        # 章节列表（最多显示前 12 章，避免溢出）
        for c in s.chapters[:12]:
            if c.done:
                mark = "[green]√[/green]"
            elif c.index == cur:
                mark = "[yellow]▶[/yellow]"
            else:
                mark = "[dim]☐[/dim]"
            lines.append(f"{mark} 第{c.index}章 {c.title}")
        if len(s.chapters) > 12:
            lines.append(f"[dim]... 共 {len(s.chapters)} 章[/dim]")
        return "\n".join(lines)

# ── 文件实时预览面板（核心，做大）─────────────────────────
"""FilePreviewPanel：像代码编辑器一样实时显示模型正在操作的文件内容。

fraction 6（约占右侧 50% 高度），追加内容时自动滚到底部（follow 开启时）。

双模式预览：
  - model 模式：模型操作文件时自动切换，显示前 1000 行（head）
  - user 模式：用户点击文件树时切换，显示完整内容（无行数限制）
  - 流式模式：模型 arguments 累积时逐字显示，不截断（实时观看写入过程）

用户点击模型正在编辑的文件时，切回 model 模式恢复实时流式进度。
"""

from __future__ import annotations

from rich.text import Text
from textual.app import ComposeResult
from textual.containers import Vertical
from textual.widgets import Label, RichLog


class FilePreviewPanel(Vertical):
    """文件实时预览面板（fraction 6，最大）。"""

    DEFAULT_CSS = """
    FilePreviewPanel {
        border: round $accent;
        height: 6fr;
        min-height: 8;
        padding: 0;
    }
    FilePreviewPanel > Label {
        dock: top;
        height: 1;
        background: $accent 20%;
        color: $text;
        padding: 0 1;
    }
    FilePreviewPanel > RichLog {
        height: 1fr;
        border: none;
        padding: 0 1;
        scrollbar-size: 1 1;
    }
    """

    title = "文件预览"

    # 模型模式：显示前 N 行（head），避免超大文件卡顿
    MAX_PREVIEW_LINES = 1000

    def __init__(self) -> None:
        super().__init__()
        self._state = None
        self._follow = True
        # 流式状态
        self._streaming = False
        self._stream_path: str | None = None
        self._stream_base: str = ""  # append 模式下文件已有内容

    def compose(self) -> ComposeResult:
        yield Label("文件预览（无）", id="preview-title")
        yield RichLog(id="preview-log", highlight=False, markup=True, auto_scroll=False, wrap=True)

    @property
    def log(self) -> RichLog:
        return self.query_one("#preview-log", RichLog)

    @property
    def title_label(self) -> Label:
        return self.query_one("#preview-title", Label)

    def set_follow(self, follow: bool) -> None:
        self._follow = follow

    # ── 最终态刷新（工具执行后 / 用户点击后）──
    def refresh_state(self, state) -> None:  # type: ignore[no-untyped-def]
        """用最新状态刷新预览（根据 preview_source 选择模式）。"""
        self._state = state
        self._follow = state.follow
        self._streaming = False  # 退出流式模式
        if not self.is_mounted or not self.query("#preview-title"):
            self.call_after_refresh(self._render_state)
            return
        self._render_state()

    def _render_state(self) -> None:
        if self._state is None:
            return
        path = self._state.preview_file
        content = self._state.preview_content
        source = self._state.preview_source
        try:
            if not path:
                self.title_label.update("文件预览（无）")
                self.log.clear()
                return
            icon = "▶" if source == "model" else "▷"
            self.title_label.update(f"{icon} {path}  ({len(content)} 字, {source})")
        except Exception:
            return
        # model 模式限制前 1000 行，user 模式无限制
        max_lines = self.MAX_PREVIEW_LINES if source == "model" else None
        self._write_to_log(content, max_lines=max_lines)

    def _write_to_log(self, content: str, max_lines: int | None = None) -> None:
        """渲染内容到 RichLog。max_lines=None 表示不截断。"""
        self.log.clear()
        if not content.strip():
            self.log.write("[dim]（空文件）[/dim]")
            return
        lines = content.splitlines()
        if max_lines is not None and len(lines) > max_lines:
            self.log.write(f"[dim]...（共 {len(lines)} 行，仅显示前 {max_lines} 行）[/dim]")
            lines = lines[:max_lines]
        for ln in lines:
            self.log.write(Text(ln))
        if self._follow:
            self.log.scroll_end()

    # ── 流式实时更新（arguments 累积时）──
    def streaming_update(self, tool_name: str, path: str, partial_text: str) -> None:
        """流式更新预览：逐句显示模型正在写入的内容。

        策略：每次收到新内容时，清空 RichLog 并按 \\n 拆行全量重写。
        RichLog.write() 每次调用必定创建新显示行，所以只有全量重写才能保证
        换行正确的同时实现实时流式效果。性能：流式内容通常几百到几千字，
        每次重写开销在毫秒级，不会造成可感知的延迟。

        - append_to_file: 显示 文件已有内容 + partial_text
        - create_novel_file/write_file: 显示 partial_text
        - edit_file: 显示 partial_text（编辑片段）
        """
        if not self.is_mounted:
            return

        # 路径变化或首次：读取 append 模式的文件已有内容
        if path != self._stream_path:
            self._stream_path = path
            self._streaming = True
            if tool_name == "append_to_file" and self._state is not None:
                root = self._state.project_root
                if root is not None:
                    fp = root / path
                    self._stream_base = fp.read_text(encoding="utf-8") if fp.exists() and fp.is_file() else ""
                else:
                    self._stream_base = ""
            else:
                self._stream_base = ""

        # 组装完整内容
        if tool_name == "append_to_file":
            display = self._stream_base + partial_text
        else:
            display = partial_text

        # 更新标题
        try:
            self.title_label.update(f"» {path}  (流式 {len(display)} 字)")
        except Exception:
            pass

        # 清空并按 \\n 拆行全量重写
        self.log.clear()
        if not display.strip():
            self.log.write("[dim]（空文件）[/dim]")
        else:
            lines = display.split("\n")
            for ln in lines[:-1]:
                self.log.write(Text(ln) if ln else Text(""))
            if lines[-1]:
                self.log.write(Text(lines[-1]))

        if self._follow:
            self.log.scroll_end()
        self.log.refresh()

    def streaming_end(self) -> None:
        """流式结束：重置状态。"""
        self._streaming = False
        self._stream_path = None
        self._stream_base = ""

# ── 文件树面板 ─────────────────────────────────
"""FileTreePanel：用 Textual Tree 控件显示项目文件树，支持点击打开预览。

点击文件节点触发 Tree.NodeSelected 事件，App 层通过 on_tree_node_selected
处理器读取文件内容并切换预览面板到 user 模式。
"""

from __future__ import annotations

from textual.app import ComposeResult
from textual.containers import Vertical
from textual.widgets import Tree

from ..state.novel_state import FileNode, NovelState


class FileTreePanel(Vertical):
    """文件树面板（fraction 2）：用 Tree 控件支持点击打开预览。"""

    DEFAULT_CSS = """
    FileTreePanel {
        border: round $primary;
        height: 1fr;
        min-height: 4;
        padding: 0;
    }
    FileTreePanel > Tree {
        height: 1fr;
        border: none;
        padding: 0 1;
        scrollbar-size: 1 1;
    }
    """

    title = "文件树"

    def __init__(self) -> None:
        super().__init__()
        self._state: NovelState | None = None

    def compose(self) -> ComposeResult:
        yield Tree("项目根", id="file-tree")

    @property
    def tree(self) -> Tree:
        return self.query_one("#file-tree", Tree)

    def refresh_state(self, state: NovelState) -> None:
        """用最新状态重建文件树。"""
        self._state = state
        if not self.is_mounted or not self.query("#file-tree"):
            self.call_after_refresh(self._rebuild)
            return
        self._rebuild()

    def _rebuild(self) -> None:
        if self._state is None:
            return
        tree = self.tree
        tree.clear()
        if not self._state.file_tree:
            return
        # 设置根节点标签为项目名
        tree.root.set_label(self._state.project_name or "项目根")
        for node in self._state.file_tree:
            self._add_node(tree.root, node)
        tree.root.expand()

    def _add_node(self, parent, node: FileNode) -> None:
        """递归添加节点到 Tree。data 存储相对路径供点击处理使用。"""
        icon = "▸ " if node.is_dir else "· "
        is_current = (not node.is_dir) and (self._state and self._state.current_file == node.path)
        label = f"{icon}{node.name}" + (" ◀" if is_current else "")
        if node.is_dir:
            child = parent.add(label, data=node.path)
            child.expand()
            for c in node.children:
                self._add_node(child, c)
        else:
            parent.add_leaf(label, data=node.path)

