# ── 待办/计划面板 ─────────────────────────────────
"""TodoPanel：显示待办列表，活跃项黄色高亮 + 自动滚动跟随。"""

from __future__ import annotations

from ..state.novel_state import NovelState
from .base import BaseRightPanel


class TodoPanel(BaseRightPanel):
    """待办面板（fraction 2）。活跃待办自动滚动到可视范围。"""

    DEFAULT_CSS = """
    TodoPanel {
        border: round $success;
        height: 1fr;
        min-height: 4;
    }
    """

    title = "待办/计划"

    def render_content(self) -> str:
        if self._state is None or not self._state.todos:
            return "[dim]暂无待办[/dim]"
        lines = []
        for i, t in enumerate(self._state.todos):
            text = t.text if len(t.text) <= 40 else t.text[:38] + ".."
            if t.done or t.status == "done":
                lines.append(f"[green]√[/green] [dim]{text}[/dim]")
            elif t.status == "active":
                lines.append(f"[yellow]▸[/yellow] [bold yellow on #333300]{text}[/bold yellow on #333300]")
            else:
                lines.append(f"[dim]○[/dim] {text}")
        return "\n".join(lines)

    def refresh_state(self, state: NovelState) -> None:
        """刷新内容后自动滚动到活跃待办。"""
        super().refresh_state(state)
        self.call_after_refresh(self._scroll_to_active)

    def _scroll_to_active(self) -> None:
        """找到活跃待办行号，自动滚动使其可见。"""
        if self._state is None:
            return
        for i, t in enumerate(self._state.todos):
            if t.status == "active" and not (t.done or t.status == "done"):
                # 滚动使活跃待办上方留 2 行上下文
                self.scroll_to(y=max(0, i - 2), animate=False)
                return

# ── 小说模式集中状态层 ─────────────────────────────────
"""NovelState：章节/待办/文件树/当前编辑文件的集中 reactive 数据源。

工具执行时修改这些字段，Textual 自动触发依赖面板的 watch_*/recompose。
为避免与 Textual reactive 的 Message 循环冲突，这里用普通 dataclass +
显式事件通知（App 通过 watch_novel_state 感知变更并刷新面板）。

常驻记忆层（Layer 1）：characters / world_settings / outline / style_guide
章节摘要层（Layer 2）：chapter_summaries
这两层会序列化注入到 system prompt，永久保留，不被上下文裁剪。
"""

from __future__ import annotations

from dataclasses import dataclass, field
from pathlib import Path


@dataclass
class ChapterInfo:
    """单章信息。"""

    index: int          # 1-based
    title: str
    done: bool = False

    def to_dict(self) -> dict:
        return {"index": self.index, "title": self.title, "done": self.done}

    @classmethod
    def from_dict(cls, data: dict) -> ChapterInfo:
        return cls(
            index=int(data.get("index", 0)),
            title=data.get("title", ""),
            done=bool(data.get("done", False)),
        )


@dataclass
class TodoItem:
    """待办项。"""

    text: str
    done: bool = False
    status: str = "pending"  # pending | active | done

    def to_dict(self) -> dict:
        return {"text": self.text, "done": self.done, "status": self.status}

    @classmethod
    def from_dict(cls, data: dict) -> TodoItem:
        return cls(
            text=data.get("text", ""),
            done=bool(data.get("done", False)),
            status=data.get("status", "done" if data.get("done") else "pending"),
        )


@dataclass
class FileNode:
    """文件树节点。"""

    name: str
    path: str
    is_dir: bool = False
    children: list[FileNode] = field(default_factory=list)


@dataclass
class NovelState:
    """小说模式运行时状态（非 reactive，由 App 持有并通过事件刷新 UI）。"""

    chapter_count: int = 0
    current_chapter: int | None = None
    chapters: list[ChapterInfo] = field(default_factory=list)
    todos: list[TodoItem] = field(default_factory=list)
    project_root: Path | None = None
    project_name: str = ""
    current_file: str | None = None          # 模型正在操作的文件（相对项目根）
    current_file_content: str = ""           # 实时内容
    file_tree: list[FileNode] = field(default_factory=list)
    follow: bool = True                      # 文件预览是否自动跟随到底部

    # ── 文件预览双模式 ──
    preview_file: str | None = None          # 当前预览的文件路径（相对项目根）
    preview_content: str = ""                # 预览文件内容
    preview_source: str = "model"            # "model"（模型操作） | "user"（用户点击）

    # ── 常驻记忆层（Layer 1）：永久保留，注入 system prompt ──
    # 人物卡：{name: {role, traits, appearance, relations}}
    characters: dict[str, dict] = field(default_factory=dict)
    # 世界观设定：{category: content}
    world_settings: dict[str, str] = field(default_factory=dict)
    # 大纲：[{index, summary}]
    outline: list[dict] = field(default_factory=list)
    # 写作风格说明
    style_guide: str = ""

    # ── 章节摘要层（Layer 2）：已完成章节的摘要，注入 system prompt ──
    # {chapter_index: summary_text}
    chapter_summaries: dict[int, str] = field(default_factory=dict)

    # ── 自定义进度（由模型通过 set_progress 工具管理，项目级持久化）──
    progress_current: int = 0
    progress_total: int = 0
    progress_label: str = ""

    # ── 预删除列表（瞬态，不持久化）──
    # 每项: {"original": Path, "pre_delete": Path, "display": str}
    _pre_delete_items: list[dict] = field(default_factory=list)

    # ── 章节工具 ──
    def set_chapter_count(self, count: int) -> str:
        self.chapter_count = max(0, count)
        # 同步扩展/收缩 chapters 列表
        while len(self.chapters) < self.chapter_count:
            self.chapters.append(ChapterInfo(index=len(self.chapters) + 1, title=f"第{len(self.chapters) + 1}章"))
        if len(self.chapters) > self.chapter_count:
            self.chapters = self.chapters[: self.chapter_count]
        # 重设章节数意味着新一季/新书开始，重置所有已完成标记
        for c in self.chapters:
            c.done = False
        return f"已设定总章数: {self.chapter_count}"

    def set_current_chapter(self, index: int, title: str = "") -> str:
        if self.chapter_count == 0:
            return "请先调用 set_chapter_count 设定总章数"
        if not (1 <= index <= self.chapter_count):
            return f"章节序号越界: {index}（总 {self.chapter_count} 章）"
        self.current_chapter = index
        self.chapters[index - 1].done = False  # 开始写某章时自动撤销完成状态
        if title:
            self.chapters[index - 1].title = title
        return f"正在写第 {index} 章: {self.chapters[index - 1].title}"

    def mark_chapter_done(self, index: int) -> str:
        if not (1 <= index <= len(self.chapters)):
            return f"章节序号越界: {index}"
        self.chapters[index - 1].done = True
        return f"第 {index} 章已标记完成"

    # ── 自定义进度工具 ──
    def set_progress(self, current: int, total: int, label: str = "") -> str:
        self.progress_current = current
        self.progress_total = total
        if label:
            self.progress_label = label
        pct = (current / total * 100) if total > 0 else 0
        return f"进度: {current}/{total} ({pct:.0f}%){' - ' + self.progress_label if self.progress_label else ''}"

    # ── 待办工具 ──
    def update_todo(self, items: list[dict]) -> str:
        self.todos = [
            TodoItem(
                text=it.get("text", ""),
                done=it.get("done", False),
                status=it.get("status", "done" if it.get("done") else "pending"),
            )
            for it in items
        ]
        return f"待办已更新（{len(self.todos)} 项）"

    def add_todo_item(self, text: str) -> str:
        self.todos.append(TodoItem(text=text))
        return f"已追加待办: {text}"

    def complete_todo_item(self, index: int) -> str:
        if not (0 <= index < len(self.todos)):
            return f"待办序号越界: {index}"
        self.todos[index].done = True
        self.todos[index].status = "done"
        return f"待办已完成: {self.todos[index].text}"

    # ── 常驻记忆工具 ──
    def update_character_card(
        self,
        name: str,
        role: str = "",
        traits: str = "",
        appearance: str = "",
        relations: str = "",
    ) -> str:
        """新增或更新人物卡。空字段不覆盖已有值。"""
        if not name:
            return "name 不能为空"
        card = self.characters.get(name, {})
        if role:
            card["role"] = role
        if traits:
            card["traits"] = traits
        if appearance:
            card["appearance"] = appearance
        if relations:
            card["relations"] = relations
        self.characters[name] = card
        return f"已更新人物卡: {name}（{card.get('role', '未设定角色')}）"

    def update_world_setting(self, category: str, content: str) -> str:
        """新增或更新世界观设定。"""
        if not category:
            return "category 不能为空"
        self.world_settings[category] = content
        return f"已更新世界观设定: {category}（{len(content)} 字）"

    def update_outline(self, chapters: list[dict]) -> str:
        """整体更新大纲。chapters: [{index, summary}]。"""
        self.outline = [
            {"index": int(c.get("index", 0)), "summary": c.get("summary", "")}
            for c in chapters
        ]
        return f"大纲已更新（{len(self.outline)} 章）"

    def update_style_guide(self, text: str) -> str:
        """更新写作风格说明。"""
        self.style_guide = text
        return f"写作风格已更新（{len(text)} 字）"

    def set_chapter_summary(self, index: int, summary: str) -> str:
        """设置某章的摘要（由 mark_chapter_done 后台摘要流程调用）。"""
        self.chapter_summaries[index] = summary
        return f"第 {index} 章摘要已保存（{len(summary)} 字）"

    # ── 常驻记忆序列化（注入 system prompt）──
    def render_memory_block(self) -> str:
        """把常驻记忆 + 章节摘要渲染成一段 markdown，供注入 system prompt。

        如果没有任何记忆，返回空字符串（调用方需自行判断是否拼接）。
        """
        lines: list[str] = []
        if self.characters:
            lines.append("【人物卡】")
            for name, card in self.characters.items():
                role = card.get("role", "")
                traits = card.get("traits", "")
                appearance = card.get("appearance", "")
                relations = card.get("relations", "")
                parts = [f"- {name}"]
                if role:
                    parts.append(f"（{role}）")
                lines.append("".join(parts))
                if traits:
                    lines.append(f"  性格: {traits}")
                if appearance:
                    lines.append(f"  外貌: {appearance}")
                if relations:
                    lines.append(f"  关系: {relations}")
        if self.world_settings:
            lines.append("【世界观设定】")
            for cat, content in self.world_settings.items():
                lines.append(f"- {cat}: {content}")
        if self.outline:
            lines.append("【大纲】")
            for ch in self.outline:
                idx = ch.get("index", "?")
                summary = ch.get("summary", "")
                lines.append(f"- 第{idx}章: {summary}")
        if self.style_guide:
            lines.append("【写作风格】")
            lines.append(self.style_guide)
        if self.chapter_summaries:
            lines.append("【已完成章节摘要】")
            for idx in sorted(self.chapter_summaries.keys()):
                lines.append(f"- 第{idx}章: {self.chapter_summaries[idx]}")
        return "\n".join(lines)

    # ── 进度统计 ──
    @property
    def done_chapter_count(self) -> int:
        return sum(1 for c in self.chapters if c.done)

    @property
    def progress_pct(self) -> float:
        if self.chapter_count == 0:
            return 0.0
        return self.done_chapter_count / self.chapter_count * 100.0

    # ── 会话级状态快照（常驻记忆 + 创作进度）──
    def save_session_state(self) -> dict:
        """导出会话级状态（常驻记忆 + 创作进度），用于持久化到 Session。

        项目级数据（chapter_count/chapters）不在此处，由 ProjectState 管理。
        """
        return {
            "novel_memory": {
                "characters": {k: dict(v) for k, v in self.characters.items()},
                "world_settings": dict(self.world_settings),
                "outline": [dict(o) for o in self.outline],
                "style_guide": self.style_guide,
                "chapter_summaries": dict(self.chapter_summaries),
            },
            "novel_progress": {
                "current_chapter": self.current_chapter,
                "todos": [t.to_dict() for t in self.todos],
            },
        }

    def restore_session_state(self, data: dict) -> None:
        """从 Session 恢复会话级状态（常驻记忆 + 创作进度）。

        不会恢复项目级数据（chapter_count/chapters），那些由 ProjectState 管理。
        """
        mem = data.get("novel_memory", {})
        self.characters = {k: dict(v) for k, v in mem.get("characters", {}).items()}
        self.world_settings = dict(mem.get("world_settings", {}))
        self.outline = [dict(o) for o in mem.get("outline", [])]
        self.style_guide = mem.get("style_guide", "")
        self.chapter_summaries = {int(k): v for k, v in mem.get("chapter_summaries", {}).items()}
        prog = data.get("novel_progress", {})
        self.current_chapter = prog.get("current_chapter")
        self.todos = [TodoItem.from_dict(t) for t in prog.get("todos", [])]

    def reset_session_state(self) -> None:
        """重置会话级状态（新建会话时调用）。

        保留项目级数据（chapter_count/chapters/project_root/project_name）。
        """
        self.characters = {}
        self.world_settings = {}
        self.outline = []
        self.style_guide = ""
        self.chapter_summaries = {}
        self.current_chapter = None
        self.todos = []

    # ── 项目级状态快照（chapter_count/chapters）──
    def save_project_state(self) -> dict:
        """导出项目级状态，用于持久化到 .Project/project_state.json。"""
        return {
            "chapter_count": self.chapter_count,
            "chapters": [c.to_dict() for c in self.chapters],
            "progress_current": self.progress_current,
            "progress_total": self.progress_total,
            "progress_label": self.progress_label,
        }

    def restore_project_state(self, data: dict) -> None:
        """从 .Project/project_state.json 恢复项目级状态。"""
        self.chapter_count = int(data.get("chapter_count", 0))
        self.chapters = [ChapterInfo.from_dict(c) for c in data.get("chapters", [])]
        self.progress_current = int(data.get("progress_current", 0))
        self.progress_total = int(data.get("progress_total", 0))
        self.progress_label = str(data.get("progress_label", ""))

# ── 项目级状态持久化 ─────────────────────────────────
"""ProjectState：小说项目级共享状态的持久化。

项目级数据（chapter_count/chapters）在同一项目的所有会话间共享，
存储于项目根目录的 .Project/project_state.json。

与 Session 的会话级数据（novel_memory/novel_progress）隔离：
- 切换会话：只切换会话级数据，项目级数据不变
- 切换项目：加载新项目的 project_state.json
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

from .novel_state import NovelState


class ProjectStateStore:
    """项目级状态读写工具。"""

    @staticmethod
    def _state_path(project_root: Path) -> Path:
        """项目状态文件路径：{project_root}/.Project/project_state.json。"""
        return project_root / ".Project" / "project_state.json"

    @staticmethod
    def _legacy_state_path(project_root: Path) -> Path:
        """旧版路径（.novel/），仅用于一次性迁移。"""
        return project_root / ".novel" / "project_state.json"

    @staticmethod
    def load(project_root: Path | None) -> dict[str, Any]:
        """从项目目录加载项目级状态。返回空 dict 表示无状态或加载失败。

        若新路径不存在但旧路径（.novel/）存在，自动迁移到 .Project/。
        """
        if project_root is None:
            return {}
        path = ProjectStateStore._state_path(project_root)
        if not path.exists():
            # 轻量迁移：旧路径存在则读取并保存到新路径
            legacy = ProjectStateStore._legacy_state_path(project_root)
            if legacy.exists():
                try:
                    with open(legacy, encoding="utf-8") as f:
                        data = json.load(f)
                    ProjectStateStore.save(project_root, data)
                    return data
                except Exception:  # noqa: BLE001
                    return {}
            return {}
        try:
            with open(path, encoding="utf-8") as f:
                return json.load(f)
        except Exception:  # noqa: BLE001
            return {}

    @staticmethod
    def save(project_root: Path | None, data: dict[str, Any]) -> None:
        """保存项目级状态到项目目录。"""
        if project_root is None:
            return
        path = ProjectStateStore._state_path(project_root)
        try:
            path.parent.mkdir(parents=True, exist_ok=True)
            with open(path, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
        except Exception:  # noqa: BLE001
            pass

    @staticmethod
    def load_to_state(state: NovelState) -> None:
        """从项目目录加载项目级状态到 NovelState。"""
        data = ProjectStateStore.load(state.project_root)
        if data:
            state.restore_project_state(data)

    @staticmethod
    def save_from_state(state: NovelState) -> None:
        """从 NovelState 保存项目级状态到项目目录。"""
        ProjectStateStore.save(state.project_root, state.save_project_state())

# ── 会话存储与多会话管理 ─────────────────────────────────
"""SessionStore：管理多个对话会话的持久化与切换。

每个会话独立保存完整上下文（messages），支持新建、列出、载入、重命名、删除。
存储于项目根目录的 sessions.json，与 config.json 解耦避免配置文件膨胀。

会话分类：
- chat 模式会话：mode="chat"，novel_project=None
- novel 模式会话：mode="novel"，novel_project=项目名
  - 每个会话独立保存常驻记忆（novel_memory）和创作进度（novel_progress）
  - 项目级共享数据（chapter_count/chapters）由 ProjectState 管理
"""

from __future__ import annotations

import uuid
from dataclasses import asdict, dataclass, field
from datetime import datetime
from pathlib import Path
from typing import Any


def _now_iso() -> str:
    """当前时间的 ISO 格式字符串（本地时区）。"""
    return datetime.now().isoformat(timespec="seconds")


def _default_novel_memory() -> dict[str, Any]:
    """会话级常驻记忆默认结构。"""
    return {
        "characters": {},
        "world_settings": {},
        "outline": [],
        "style_guide": "",
        "chapter_summaries": {},
    }


def _default_novel_progress() -> dict[str, Any]:
    """会话级创作进度默认结构。"""
    return {
        "current_chapter": None,
        "todos": [],
    }


@dataclass
class Session:
    """单个对话会话。"""

    id: str
    name: str
    mode: str  # "chat" | "novel"
    messages: list[dict[str, Any]] = field(default_factory=list)
    created_at: str = ""
    updated_at: str = ""
    # novel 模式下关联的项目名（便于恢复时提示）
    novel_project: str | None = None
    # 会话级常驻记忆（仅 novel 模式有效，per-session 隔离）
    novel_memory: dict[str, Any] = field(default_factory=_default_novel_memory)
    # 会话级创作进度（仅 novel 模式有效，per-session 隔离）
    novel_progress: dict[str, Any] = field(default_factory=_default_novel_progress)

    def touch(self) -> None:
        self.updated_at = _now_iso()

    @classmethod
    def create(cls, name: str, mode: str, novel_project: str | None = None) -> Session:
        now = _now_iso()
        return cls(
            id=uuid.uuid4().hex[:8],
            name=name or "新会话",
            mode=mode,
            messages=[],
            created_at=now,
            updated_at=now,
            novel_project=novel_project,
        )

    def to_dict(self) -> dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: dict[str, Any]) -> Session:
        return cls(
            id=data.get("id", uuid.uuid4().hex[:8]),
            name=data.get("name", "未命名"),
            mode=data.get("mode", "chat"),
            messages=data.get("messages", []),
            created_at=data.get("created_at", ""),
            updated_at=data.get("updated_at", ""),
            novel_project=data.get("novel_project"),
            # 兼容旧会话：没有 novel_memory/novel_progress 字段时用默认值
            novel_memory={**_default_novel_memory(), **data.get("novel_memory", {})},
            novel_progress={**_default_novel_progress(), **data.get("novel_progress", {})},
        )


class SessionStore:
    """多会话持久化管理。"""

    def __init__(self, path: Path) -> None:
        self.path = path
        self.sessions: dict[str, Session] = {}
        self.load()

    def load(self) -> None:
        """从磁盘加载所有会话。"""
        self.sessions.clear()
        if not self.path.exists():
            return
        try:
            import json

            with open(self.path, encoding="utf-8") as f:
                data = json.load(f)
            for sid, sdata in data.get("sessions", {}).items():
                session = Session.from_dict(sdata)
                self.sessions[session.id] = session
        except Exception:
            # 损坏的文件不阻塞启动
            self.sessions.clear()

    def save(self) -> None:
        """持久化所有会话到磁盘。"""
        try:
            import json

            data = {
                "sessions": {sid: s.to_dict() for sid, s in self.sessions.items()},
                "version": 2,
            }
            self.path.parent.mkdir(parents=True, exist_ok=True)
            with open(self.path, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    # ── 会话操作 ──
    def create(self, name: str, mode: str, novel_project: str | None = None) -> Session:
        """新建会话并持久化。"""
        session = Session.create(name, mode, novel_project)
        self.sessions[session.id] = session
        self.save()
        return session

    def list_sessions(
        self,
        mode: str | None = None,
        project: str | None = None,
    ) -> list[Session]:
        """按更新时间降序返回会话，支持按模式/项目过滤。

        - mode="chat"：只返回 chat 会话
        - mode="novel" + project="xxx"：只返回该项目的 novel 会话
        - 都不传：返回所有会话
        """
        result = list(self.sessions.values())
        if mode:
            result = [s for s in result if s.mode == mode]
        if project:
            result = [s for s in result if s.novel_project == project]
        return sorted(result, key=lambda s: s.updated_at, reverse=True)

    def get(self, sid: str) -> Session | None:
        return self.sessions.get(sid)

    def delete(self, sid: str) -> bool:
        if sid in self.sessions:
            del self.sessions[sid]
            self.save()
            return True
        return False

    def rename(self, sid: str, name: str) -> bool:
        session = self.sessions.get(sid)
        if session is None:
            return False
        session.name = name
        session.touch()
        self.save()
        return True

    def update_messages(self, sid: str, messages: list[dict[str, Any]]) -> None:
        """更新某会话的消息列表并刷新时间戳。"""
        session = self.sessions.get(sid)
        if session is None:
            return
        session.messages = [dict(m) for m in messages]
        session.touch()
        self.save()

    def count(self) -> int:
        return len(self.sessions)

# ── 章节工具 ─────────────────────────────────
"""章节工具：set_chapter_count / set_current_chapter / mark_chapter_done。"""

from __future__ import annotations

from typing import Any

from ..state.novel_state import NovelState
from .registry import ToolDef


def _set_chapter_count(state: NovelState, args: dict[str, Any]) -> str:
    return state.set_chapter_count(int(args.get("count", 0)))


def _set_current_chapter(state: NovelState, args: dict[str, Any]) -> str:
    return state.set_current_chapter(int(args.get("index", 0)), args.get("title", ""))


def _mark_chapter_done(state: NovelState, args: dict[str, Any]) -> str:
    return state.mark_chapter_done(int(args.get("index", 0)))


def _set_progress(state: NovelState, args: dict[str, Any]) -> str:
    return state.set_progress(
        int(args.get("current", 0)),
        int(args.get("total", 0)),
        args.get("label", ""),
    )


CHAPTER_TOOL_DEFS: list[ToolDef] = [
    ToolDef(
        name="set_chapter_count",
        description="设定小说总章数。开始创作时调用。",
        parameters={
            "type": "object",
            "properties": {"count": {"type": "integer", "description": "总章数"}},
            "required": ["count"],
        },
        handler=_set_chapter_count,
    ),
    ToolDef(
        name="set_current_chapter",
        description="声明正在写第几章。每次切换章节时调用，右侧面板会高亮当前章。",
        parameters={
            "type": "object",
