# ── 左侧聊天消息流 ─────────────────────────────────
"""ChatView：基于 RichLog 的滚动消息流，展示用户/思考/回答/工具调用。

流式输出时使用行缓冲：按 \\n 分行累积，避免每个碎片 chunk 占一行
（RichLog 每次 write 都换行，若每个小 chunk 单独 write 会变成每字一行）。
"""

from __future__ import annotations

from typing import Any

from rich.text import Text
from textual.widgets import RichLog

# 缓冲超过此长度时强制 flush（即使没有换行符），保证长文本实时性
DEFAULT_FLUSH_THRESHOLD = 80


class ChatView(RichLog):
    """聊天消息流。"""

    DEFAULT_CSS = """
    ChatView {
        border: round $primary;
        background: $surface;
        padding: 0 1;
        scrollbar-size: 1 1;
    }
    ChatView:focus { border: round $accent; }
    """

    def __init__(self, flush_threshold: int | None = None, **kwargs: Any) -> None:
        super().__init__(highlight=False, markup=True, auto_scroll=True, wrap=True, **kwargs)
        self._think_buf: str = ""
        self._answer_buf: str = ""
        # 允许通过 config.json 的 ui.flush_threshold 覆盖默认值
        self._flush_threshold: int = (
            flush_threshold if flush_threshold is not None else DEFAULT_FLUSH_THRESHOLD
        )

    # ── 行缓冲核心 ──
    def _append_buf(self, text: str, buf_name: str, style: str) -> None:
        """追加文本到缓冲，按换行符分行写出，剩余留缓冲。"""
        buf = self._think_buf if buf_name == "think" else self._answer_buf
        buf += text
        # 按换行符分割：完整行立即写出，最后一段留缓冲
        while "\n" in buf:
            line, buf = buf.split("\n", 1)
            if line:
                self.write(Text(line, style=style))
            else:
                self.write(Text(""))
        # 缓冲过长时强制写出，保证实时性
        if len(buf) >= self._flush_threshold:
            self.write(Text(buf, style=style))
            buf = ""
        if buf_name == "think":
            self._think_buf = buf
        else:
            self._answer_buf = buf

    def _flush_buf(self, buf_name: str, style: str) -> None:
        """写出缓冲区剩余内容。"""
        if buf_name == "think":
            if self._think_buf:
                self.write(Text(self._think_buf, style=style))
                self._think_buf = ""
        else:
            if self._answer_buf:
                self.write(Text(self._answer_buf, style=style))
                self._answer_buf = ""

    # ── 各类消息写入 ──
    def write_user(self, text: str) -> None:
        self.write(Text(f"你> {text}", style="bold green"))

    def write_thinking(self, text: str) -> None:
        # 思考内容灰色斜体，行缓冲后写入
        self._append_buf(text, "think", "dim italic")

    def write_thinking_start(self) -> None:
        self.write(Text("┌─ 思考过程 " + "─" * 40, style="yellow"))

    def write_thinking_end(self) -> None:
        self._flush_buf("think", "dim italic")
        self.write(Text("└" + "─" * 52, style="yellow"))

    def write_answer_start(self) -> None:
        self.write(Text("─" * 20 + " 回答 " + "─" * 20, style="bold"))

    def write_answer(self, text: str) -> None:
        self._append_buf(text, "answer", "white")

    def write_tool_call(self, summary: str) -> None:
        """工具调用摘要（折叠为单行）。"""
        # 工具调用前先 flush 思考与回答缓冲，避免顺序错乱或工具调用嵌在思考块里
        self._flush_buf("think", "dim italic")
        self._flush_buf("answer", "white")
        self.write(Text(f"◆ {summary}", style="cyan"))

    def write_tool_calling(self, tool_name: str) -> None:
        """工具开始调用（实时提示，参数流式接收中）。"""
        self._flush_buf("think", "dim italic")
        self._flush_buf("answer", "white")
        self.write(Text(f"→ 正在调用 {tool_name}", style="yellow"))

    def write_info(self, text: str) -> None:
        self._flush_buf("answer", "white")
        self.write(Text(text, style="cyan"))

    def write_warn(self, text: str) -> None:
        self._flush_buf("answer", "white")
        self.write(Text(text, style="yellow"))

    def write_error(self, text: str) -> None:
        self._flush_buf("answer", "white")
        self.write(Text(text, style="red"))

    def write_separator(self) -> None:
        # 分隔前 flush 所有缓冲
        self._flush_buf("think", "dim italic")
        self._flush_buf("answer", "white")
        self.write(Text(""))

# ── 底部输入栏 ─────────────────────────────────
"""InputBar：基于 textual TextArea 的多行输入栏，Enter 提交、Shift+Enter 换行，支持斜杠命令。

功能：
  - 多行编辑：Shift+Enter 换行，Enter 提交
  - ↑/↓ 在光标位于首行/末行时翻阅历史输入；补全列表激活时改为上下选择候选
  - Tab 用当前高亮候选补全斜杠命令（预选中 + 用法提示）
  - 历史持久化（由 App 通过 config.json 管理）

设计说明：传统终端无法区分 Shift+Enter 与 Enter（都发送 0x0D），
但 Windows API GetAsyncKeyState 可在 OS 层面实时查询 Shift 键按下状态，
从而在收到 Enter 时判断是"Enter 提交"还是"Shift+Enter 换行"。
此方案完全绕过终端协议限制。
"""

from __future__ import annotations

import ctypes

from textual import events
from textual.app import ComposeResult
from textual.containers import Horizontal, Vertical
from textual.widgets import Label, OptionList, Static, TextArea

from ..commands import match_commands

# Windows 虚拟键码
VK_SHIFT = 0x10
VK_CONTROL = 0x11


def _is_key_held(vk: int) -> bool:
    """检测某个虚拟键当前是否被按住（OS 级查询，绕过终端协议）。"""
    return bool(ctypes.windll.user32.GetAsyncKeyState(vk) & 0x8000)


class HistoryInput(TextArea):
    """带历史导航与 Tab 补全的多行输入框。

    Enter 提交，Shift+Enter 换行（借助 GetAsyncKeyState 检测 Shift 键）。
    上/下键在光标位于首行/末行时翻阅历史输入；补全列表激活时选择候选。
    历史记录由外部通过 set_history / input_history 属性管理持久化。
    """

    # 无组合键绑定，所有处理在 on_key 中手动完成。
    BINDINGS = []

    def __init__(self, *args: object, history: list[str] | None = None, **kwargs: object) -> None:
        super().__init__(*args, **kwargs)  # type: ignore[arg-type]
        self._history: list[str] = list(history or [])
        # 当前历史游标位置：len(history) 表示"草稿区"（未提交的当前输入）
        self._history_index: int = len(self._history)
        # 草稿：用户在浏览历史时未提交的输入，按↓回到末尾时恢复
        self._draft: str = ""
        # 补全状态
        self._completion_index: int = 0
        # 回调：通知 InputBar 更新补全提示
        self._on_completion_change: callable | None = None  # type: ignore[type-arg]
        # 回调：提交（Shift+Enter 触发，由 App 注入）
        self._on_submit: callable | None = None  # type: ignore[type-arg]

    def set_completion_callback(self, callback: callable) -> None:  # type: ignore[type-arg]
        """设置补全变化时的回调（由 InputBar 注入）。"""
        self._on_completion_change = callback

    def set_submit_callback(self, callback: callable) -> None:  # type: ignore[type-arg]
        """设置提交回调（由 App 注入，Shift+Enter 触发）。"""
        self._on_submit = callback

    # ── 按键处理 ──
    def on_key(self, event: events.Key) -> None:
        # Enter：用 GetAsyncKeyState 检测 Shift 是否被按住（OS 级，绕过终端协议）
        if event.key == "enter":
            if _is_key_held(VK_SHIFT):
                # Shift+Enter → 换行（手动插入换行符）
                event.prevent_default()
                event.stop()
                self.replace("\n", self.cursor_location, self.cursor_location)
                row, _ = self.cursor_location
                self.move_cursor((row + 1, 0))
                return
            # 纯 Enter → 提交
            event.prevent_default()
            event.stop()
            if self._on_submit:
                self._on_submit()
            return
        if event.key == "up":
            # 补全列表激活时优先选择候选
            if self._on_completion_change and self._on_completion_change("up"):
                event.prevent_default()
                event.stop()
                return
            # 光标在首行时翻阅历史，否则走默认光标移动
            if self.cursor_at_first_line:
                self._navigate(-1)
                event.prevent_default()
                event.stop()
        elif event.key == "down":
            if self._on_completion_change and self._on_completion_change("down"):
                event.prevent_default()
                event.stop()
                return
            # 光标在末行时翻阅历史，否则走默认光标移动
            if self.cursor_at_last_line:
                self._navigate(1)
                event.prevent_default()
                event.stop()
        elif event.key == "tab":
            # Tab 补全：由 InputBar 的补全逻辑处理，阻止默认 Tab 缩进
            handled = self._try_complete()
            if handled:
                event.prevent_default()
                event.stop()
        elif event.key == "escape":
            # Esc 关闭补全提示
            if self._on_completion_change and self._on_completion_change("escape"):
                event.prevent_default()
                event.stop()

    def _navigate(self, direction: int) -> None:
        """direction<0 向上（更早的历史），direction>0 向下（更新的历史）。"""
        if direction < 0:
            if not self._history or self._history_index <= 0:
                return
            # 进入历史前保存当前草稿
            if self._history_index == len(self._history):
                self._draft = self.text
            self._history_index -= 1
            self.load_text(self._history[self._history_index])
            self._move_cursor_to_end()
        else:
            if self._history_index >= len(self._history):
                return
            self._history_index += 1
            if self._history_index == len(self._history):
                # 回到草稿区
                self.load_text(self._draft)
            else:
                self.load_text(self._history[self._history_index])
            self._move_cursor_to_end()

    def _move_cursor_to_end(self) -> None:
        """移动光标到文本末尾。"""
        line_count = self.document.line_count
        last_line = self.document[line_count - 1] if line_count > 0 else ""
        self.move_cursor((line_count - 1, len(last_line)))

    # ── Tab 补全 ──
    def _try_complete(self) -> bool:
        """尝试 Tab 补全。返回 True 表示已处理。"""
        if not self._on_completion_change:
            return False
        return self._on_completion_change("tab")

    # ── 历史管理 ──
    def record_history(self, value: str) -> None:
        """提交后记录一条历史。空值与连续重复会被忽略。"""
        if not value.strip():
            return
        # 避免连续重复记录
        if self._history and self._history[-1] == value:
            self._history_index = len(self._history)
            self._draft = ""
            return
        self._history.append(value)
        self._history_index = len(self._history)
        self._draft = ""

    @property
    def input_history(self) -> list[str]:
        """返回历史列表的副本。"""
        return list(self._history)

    def set_history(self, history: list[str]) -> None:
        """从外部加载历史（启动时从 config 恢复）。"""
        self._history = list(history)
        self._history_index = len(self._history)
        self._draft = ""

    def clear(self) -> None:
        """清空输入框。"""
        self.load_text("")
        self._draft = ""


class InputBar(Vertical):
    """输入栏：补全提示行 + 提示符 + 多行输入框。"""

    DEFAULT_CSS = """
    InputBar {
        height: auto;
        padding: 0;
        border: none;
    }
    InputBar > Horizontal {
        height: auto;
        padding: 0;
    }
    InputBar > Horizontal > Label {
        width: 3;
        height: 5;
        color: $success;
        content-align: left middle;
        padding: 0 0 0 1;
    }
    InputBar > Horizontal > TextArea {
        width: 1fr;
        height: 5;
        border: round $primary;
        padding: 0 1;
    }
    InputBar > Horizontal > TextArea:focus {
        border: round $accent;
    }
    #completion-hint {
        height: auto;
        max-height: 9;
        padding: 0 1;
        background: $boost;
        display: none;
    }
    #completion-hint.visible {
        display: block;
    }
    #completion-list {
        height: 6;
        border: none;
        padding: 0;
        background: transparent;
        color: $text;
    }
    #completion-list:focus {
        border: none;
    }
    #completion-list > .option-list--option {
        padding: 0;
    }
    #completion-list > .option-list--option-highlighted {
        color: $accent;
        background: transparent;
        text-style: bold;
    }
    #completion-detail {
        height: auto;
        color: $text-muted;
        padding-top: 1;
    }
    """

    def __init__(self) -> None:
        super().__init__()
        self._current_mode: str = "chat"
        # 当前匹配的命令列表
        self._matches: list[tuple[str, dict]] = []  # type: ignore[type-arg]
        self._completion_index: int = 0

    def compose(self) -> ComposeResult:
        with Vertical(id="completion-hint"):
            option_list = OptionList(id="completion-list")
            option_list.can_focus = False
            yield option_list
            yield Static("", id="completion-detail")
        with Horizontal():
            yield Label(">")
            yield HistoryInput(id="chat-input", soft_wrap=True, show_line_numbers=False)

    def on_mount(self) -> None:
        input_widget = self.query_one(HistoryInput)
        input_widget.set_completion_callback(self._handle_completion_request)

    @property
    def input(self) -> HistoryInput:
        return self.query_one("#chat-input", HistoryInput)

    def set_mode(self, mode: str) -> None:
        """设置当前模式（用于过滤模式专属命令）。"""
        self._current_mode = mode

    def focus_input(self) -> None:
        self.input.focus()

    def clear(self) -> None:
        self.input.clear()

    # ── 补全逻辑 ──
    def on_text_area_changed(self, event: TextArea.Changed) -> None:
        """输入变化时更新补全提示。"""
        if event.text_area.id != "chat-input":
            return
        value = event.text_area.text
        # 命令补全仅在第一行以 / 开头且无空格时触发
        first_line = value.split("\n", 1)[0]
        if value.startswith("/") and "\n" not in value and " " not in value:
            # 命令补全模式
            self._matches = match_commands(value, self._current_mode)
            self._completion_index = 0
            self._update_hint()
        else:
            self._matches = []
            self._update_hint()

    def _handle_completion_request(self, action: str) -> bool:
        """处理来自 HistoryInput 的补全请求。返回 True 表示已处理。"""
        if not self._matches:
            return False
        if action == "up":
            # 向上移动高亮（循环），不修改输入框内容
            self._completion_index = (self._completion_index - 1) % len(self._matches)
            self._update_hint()
            return True
        elif action == "down":
            # 向下移动高亮（循环），不修改输入框内容
            self._completion_index = (self._completion_index + 1) % len(self._matches)
            self._update_hint()
            return True
        elif action == "tab":
            # 用当前高亮候选填充输入框（加空格便于继续输入参数）
            cmd, _ = self._matches[self._completion_index]
            self.input.load_text(cmd + " ")
            self.input._move_cursor_to_end()
            self._update_hint()
            return True
        elif action == "escape":
            # 关闭补全提示
            self._matches = []
            self._update_hint()
            return True
        return False

    def _update_hint(self) -> None:
        """更新补全提示：列表区 + 统一底部详情区。"""
        hint = self.query_one("#completion-hint", Vertical)
        option_list = self.query_one("#completion-list", OptionList)
        detail_static = self.query_one("#completion-detail", Static)

        if not self._matches:
            option_list.clear_options()
            detail_static.update("")
            hint.remove_class("visible")
            return

        # 列表区：每个候选一条 Option，OptionList 负责高亮与滚动
        options = [
            f"{'▶' if i == self._completion_index else ' '} {cmd:<12} {meta['desc']}"
            for i, (cmd, meta) in enumerate(self._matches)
        ]
        option_list.set_options(options)
        option_list.highlighted = self._completion_index

        self._update_detail()
        hint.add_class("visible")

    def _update_detail(self) -> None:
        """更新底部详情区（用法、说明、操作提示）。"""
        detail_static = self.query_one("#completion-detail", Static)
        if not self._matches:
            detail_static.update("")
            return
        cmd, meta = self._matches[self._completion_index]
        detail_lines = [
            f"用法: {meta['usage']}",
            f"说明: {meta['detail']}",
            f"↑↓ 选择 · Tab 补全 · Esc 关闭 · 共 {len(self._matches)} 条",
        ]
        detail_static.update("\n".join(detail_lines))

    def on_option_list_option_highlighted(
        self, event: OptionList.OptionHighlighted
    ) -> None:
        """鼠标点击导致 OptionList 高亮变化时同步内部索引并刷新详情。"""
        if event.option_list.id != "completion-list":
            return
        if event.option_index == self._completion_index:
            return
        self._completion_index = event.option_index
        self._update_detail()

    def on_key(self, event: events.Key) -> None:
        # Ctrl+M 等全局快捷键由 App 处理；这里仅透传
        pass

# ── 会话选择模态屏 ─────────────────────────────────
"""SessionsScreen：模态屏展示历史会话列表，支持选择/新建/删除。

按键：
  ↑/↓ 或 j/k  上下移动
  Enter       载入选中会话
  n           新建会话（载入空白会话，由 App 处理）
  d           删除选中会话（二次确认）
  Esc         关闭
"""

from __future__ import annotations

from datetime import datetime

from textual.app import ComposeResult
from textual.binding import Binding
from textual.containers import Vertical
from textual.screen import ModalScreen
from textual.widgets import Footer, Label, ListItem, ListView

from ..state.session_store import Session


def _format_time(iso: str) -> str:
    """ISO 时间转可读格式，失败则原样返回。"""
    if not iso:
        return "-"
    try:
        dt = datetime.fromisoformat(iso)
        return dt.strftime("%m-%d %H:%M")
    except ValueError:
        return iso


def _session_label(session: Session, index: int, current_id: str | None) -> str:
    """构造列表项显示文本。"""
    mode_tag = "小说" if session.mode == "novel" else "聊天"
    msg_count = len(session.messages)
    time_str = _format_time(session.updated_at)
    cur = " ★" if session.id == current_id else ""
    name = session.name or "未命名"
    return f"#{index + 1:<2} [{mode_tag}] {name}  ({msg_count}条, {time_str}){cur}"


class SessionsScreen(ModalScreen[str | None]):
    """会话选择模态屏。

    返回值：
      - Session.id：载入该会话
      - "__new__"：新建会话
      - None：取消
    """

    CSS = """
    SessionsScreen {
        align: center middle;
    }
    SessionsScreen > Vertical {
        width: 80;
        max-width: 90%;
        height: 28;
        max-height: 80%;
        border: round $accent;
        background: $surface;
        padding: 1 2;
    }
    SessionsScreen > Vertical > Label.title {
        color: $accent;
        text-align: center;
        text-style: bold;
        margin-bottom: 1;
    }
    SessionsScreen > Vertical > ListView {
        height: 1fr;
        border: round $primary;
    }
    SessionsScreen > Vertical > Label.hint {
        color: $text-muted;
        margin-top: 1;
    }
    """

    BINDINGS = [
        Binding("escape", "cancel", "关闭", show=True),
        Binding("n", "new", "新建", show=True),
        Binding("d", "delete", "删除", show=True),
    ]

    def __init__(self, sessions: list[Session], current_id: str | None) -> None:
        super().__init__()
        self._sessions = sessions
        self._current_id = current_id

    def compose(self) -> ComposeResult:
        with Vertical():
            yield Label("历史会话（↑↓选择 · Enter载入 · n新建 · d删除 · Esc关闭）", classes="title")
            if not self._sessions:
                yield Label("（暂无历史会话，按 n 新建）", classes="hint")
            else:
                items = [
                    ListItem(Label(_session_label(s, i, self._current_id)))
                    for i, s in enumerate(self._sessions)
                ]
                yield ListView(*items, id="sessions-list")
            yield Label("提示：★ 标记当前会话", classes="hint")
        yield Footer()

    def on_mount(self) -> None:
        try:
            lv = self.query_one("#sessions-list", ListView)
            lv.focus()
            # 默认高亮当前会话
            if self._current_id:
                for i, s in enumerate(self._sessions):
                    if s.id == self._current_id:
                        lv.index = i
                        break
        except Exception:
            pass

    # ── 动作 ──
    def action_cancel(self) -> None:
        self.dismiss(None)

    def on_list_view_selected(self, event: ListView.Selected) -> None:
        """ListView 选中项事件（Enter 键触发）。"""
        # 通过 item 的索引找到对应会话
        try:
            lv = self.query_one("#sessions-list", ListView)
            idx = lv.index
            if idx is None or idx >= len(self._sessions):
                self.dismiss(None)
                return
            self.dismiss(self._sessions[idx].id)
        except Exception:
            self.dismiss(None)

    def action_new(self) -> None:
        self.dismiss("__new__")

    def action_delete(self) -> None:
        try:
            lv = self.query_one("#sessions-list", ListView)
            idx = lv.index
            if idx is None or idx >= len(self._sessions):
                return
            session = self._sessions[idx]
            # 简单二次确认：再按一次 d 才删除
            if getattr(self, "_confirm_delete", None) == idx:
                self._sessions.pop(idx)
                lv.clear()
                for i, s in enumerate(self._sessions):
                    lv.append(ListItem(Label(_session_label(s, i, self._current_id))))
                # 通过特殊返回值通知 App 删除
                self.dismiss(f"__delete__:{session.id}")
            else:
                self._confirm_delete = idx
                # 更新提示
                try:
                    hint = self.query_one("Vertical > Label.hint", Label)
                    hint.update(f"再按一次 d 确认删除：{session.name}（按其他键取消）")
                except Exception:
                    pass
        except Exception:
            pass

    def on_key(self, event) -> None:  # noqa: ANN001
        # 任意非 d 键取消删除确认
        if event.key != "d" and getattr(self, "_confirm_delete", None) is not None:
            self._confirm_delete = None
            try:
                hint = self.query_one("Vertical > Label.hint", Label)
                hint.update("提示：★ 标记当前会话")
            except Exception:
                pass
